38	/**
39	 * A {@link Runnable} to be used as a {@link Runtime#addShutdownHook(Thread) shutdown
40	 * hook} to perform graceful shutdown of Spring Boot applications. This hook tracks
41	 * registered application contexts as well as any actions registered via
42	 * {@link SpringApplication#getShutdownHandlers()}.
43	 *
44	 * @author Andy Wilkinson
45	 * @author Phillip Webb
46	 * @author Brian Clozel
47	 */
48	class SpringApplicationShutdownHook implements Runnable {
49	
50		private static final int SLEEP = 50;
51	
52		private static final long TIMEOUT = TimeUnit.MINUTES.toMillis(10);
53	
54		private static final Log logger = LogFactory.getLog(SpringApplicationShutdownHook.class);
55	
56		private final Handlers handlers = new Handlers();
57	
58		private final Set<ConfigurableApplicationContext> contexts = new LinkedHashSet<>();
59	
60		private final Set<ConfigurableApplicationContext> closedContexts = Collections.newSetFromMap(new WeakHashMap<>());
61	
62		private final ApplicationContextClosedListener contextCloseListener = new ApplicationContextClosedListener();
63	
64		private final AtomicBoolean shutdownHookAdded = new AtomicBoolean();
65	
66		private volatile boolean shutdownHookAdditionEnabled;
67	
68		private boolean inProgress;
69	
70		SpringApplicationShutdownHandlers getHandlers() {
71			return this.handlers;
72		}
73	
74		void enableShutdownHookAddition() {
75			this.shutdownHookAdditionEnabled = true;
76		}
77	
78		void registerApplicationContext(ConfigurableApplicationContext context) {
79			addRuntimeShutdownHookIfNecessary();
80			synchronized (SpringApplicationShutdownHook.class) {
81				assertNotInProgress();
82				context.addApplicationListener(this.contextCloseListener);
83				this.contexts.add(context);
84			}
85		}
86	
87		private void addRuntimeShutdownHookIfNecessary() {
88			if (this.shutdownHookAdditionEnabled && this.shutdownHookAdded.compareAndSet(false, true)) {
89				addRuntimeShutdownHook();
90			}
91		}
92	
93		void addRuntimeShutdownHook() {
94			Runtime.getRuntime().addShutdownHook(new Thread(this, "SpringApplicationShutdownHook"));
95		}
96	
97		void deregisterFailedApplicationContext(ConfigurableApplicationContext applicationContext) {
98			synchronized (SpringApplicationShutdownHook.class) {
99				Assert.state(!applicationContext.isActive(), "Cannot unregister active application context");
100				SpringApplicationShutdownHook.this.contexts.remove(applicationContext);
101			}
102		}
103	
104		@Override
105		public void run() {
106			Set<ConfigurableApplicationContext> contexts;
107			Set<ConfigurableApplicationContext> closedContexts;
108			List<Handler> handlers;
109			synchronized (SpringApplicationShutdownHook.class) {
110				this.inProgress = true;
111				contexts = new LinkedHashSet<>(this.contexts);
112				closedContexts = new LinkedHashSet<>(this.closedContexts);
113				handlers = new ArrayList<>(this.handlers.getActions());
114				Collections.reverse(handlers);
115			}
116			contexts.forEach(this::closeAndWait);
117			closedContexts.forEach(this::closeAndWait);
118			handlers.forEach(Handler::run);
119		}
120	
121		boolean isApplicationContextRegistered(ConfigurableApplicationContext context) {
122			synchronized (SpringApplicationShutdownHook.class) {
123				return this.contexts.contains(context);
124			}
125		}
126	
127		void reset() {
128			synchronized (SpringApplicationShutdownHook.class) {
129				this.contexts.clear();
130				this.closedContexts.clear();
131				this.handlers.getActions().clear();
132				this.inProgress = false;
133			}
134		}
135	
136		/**
137		 * Call {@link ConfigurableApplicationContext#close()} and wait until the context
138		 * becomes inactive. We can't assume that just because the close method returns that
139		 * the context is actually inactive. It could be that another thread is still in the
140		 * process of disposing beans.
141		 * @param context the context to clean
142		 */
143		private void closeAndWait(ConfigurableApplicationContext context) {
144			if (!context.isActive()) {
145				return;
146			}
147			context.close();
148			try {
149				int waited = 0;
150				while (context.isActive()) {
151					if (waited > TIMEOUT) {
152						throw new TimeoutException();
153					}
154					Thread.sleep(SLEEP);
155					waited += SLEEP;
156				}
157			}
158			catch (InterruptedException ex) {
159				Thread.currentThread().interrupt();
160				logger.warn("Interrupted waiting for application context " + context + " to become inactive");
161			}
162			catch (TimeoutException ex) {
163				logger.warn("Timed out waiting for application context " + context + " to become inactive", ex);
164			}
165		}
166	
167		private void assertNotInProgress() {
168			Assert.state(!SpringApplicationShutdownHook.this.inProgress, "Shutdown in progress");
169		}
170	
171		/**
172		 * The handler actions for this shutdown hook.
173		 */
