241		 */
242		private final class ApplicationContextClosedListener implements ApplicationListener<ContextClosedEvent> {
243	
244			@Override
245			public void onApplicationEvent(ContextClosedEvent event) {
246				// The ContextClosedEvent is fired at the start of a call to {@code close()}
247				// and if that happens in a different thread then the context may still be
248				// active. Rather than just removing the context, we add it to a {@code
249				// closedContexts} set. This is weak set so that the context can be GC'd once
250				// the {@code close()} method returns.
251				synchronized (SpringApplicationShutdownHook.class) {
252					ApplicationContext applicationContext = event.getApplicationContext();
253					SpringApplicationShutdownHook.this.contexts.remove(applicationContext);
254					SpringApplicationShutdownHook.this.closedContexts
255						.add((ConfigurableApplicationContext) applicationContext);
256				}
257			}
258	
259		}
